.footer-section h4 {
	color: var(--text-primary);
	margin-bottom: 20px;
	text-transform: uppercase;
	letter-spacing: 1px;
	font-size: 16px;
}

.footer-links {
	display: flex;
	flex-direction: column;
	gap: 10px;
}

.footer-links a {
	color: var(--text-secondary);
	text-decoration: none;
	transition: all 0.3s ease;
	font-size: 14px;
}

.footer-links a:hover {
	color: var(--accent-purple);
	padding-left: 10px;
}

.footer-bottom {
	padding-top: 30px;
	border-top: 1px solid var(--metal-dark);
	display: flex;
	justify-content: space-between;
	align-items: center;
	max-width: 1200px;
	margin: 0 auto;
}

.copyright {
	color: var(--text-dim);
	font-size: 14px;
}

.footer-credits {
	color: var(--text-dim);
	font-size: 14px;
}

.footer-credits a {
	color: var(--accent-purple);
	text-decoration: none;
}

.footer-credits a:hover {
	text-decoration: underline;
}

/* Responsive Design */
@media (max-width: 1024px) {
	.carousel-item {
		width: 350px;
		height: 480px;
